#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long P;
        scanf("%lld", &P);
        long long ans = P / 2 + 1;
        printf("%lld\n", ans);
    }
    return 0;
}

